/* ============ Load Model Weights ============ */

int read_int_from(char **p) {
    char *d;
    int v;
    d = *p;
    v = (d[0] & 0xFF) | ((d[1] & 0xFF) << 8) | ((d[2] & 0xFF) << 16) | ((d[3] & 0xFF) << 24);
    *p = d + 4;
    return v;
}

/* Simple string compare (no strcmp needed) */
int str_eq(char *a, char *b) {
    while (*a && *b) {
        if (*a != *b) return 0;
        a = a + 1;
        b = b + 1;
    }
    return *a == *b;
}

void init_subgraph_storage() {
    int i;
    int j;

    MAX_TENSORS = 256;
    MAX_SUBGRAPHS = 32;
    MAX_SG_NODES = 16;
    MAX_SG_IO = 8;

    g_tensor_data = malloc(MAX_TENSORS * sizeof(int *));
    g_tensor_size = malloc(MAX_TENSORS * sizeof(int));
    g_tensor_ndims = malloc(MAX_TENSORS * sizeof(int));
    g_tensor_dims = malloc(MAX_TENSORS * sizeof(int *));
    g_sparse_idx = malloc(MAX_TENSORS * sizeof(int *));
    g_sparse_val = malloc(MAX_TENSORS * sizeof(int *));
    g_sparse_nnz = malloc(MAX_TENSORS * sizeof(int));

    i = 0;
    while (i < MAX_TENSORS) {
        g_tensor_data[i] = 0;
        g_tensor_size[i] = 0;
        g_tensor_ndims[i] = 0;
        g_tensor_dims[i] = malloc(8 * sizeof(int));
        g_sparse_idx[i] = 0;
        g_sparse_val[i] = 0;
        g_sparse_nnz[i] = 0;
        i = i + 1;
    }
    g_num_tensors = 0;

    sg_names = malloc(MAX_SUBGRAPHS * sizeof(char *));
    sg_num_inputs = malloc(MAX_SUBGRAPHS * sizeof(int));
    sg_num_outputs = malloc(MAX_SUBGRAPHS * sizeof(int));
    sg_num_temps = malloc(MAX_SUBGRAPHS * sizeof(int));
    sg_temp_sizes = malloc(MAX_SUBGRAPHS * sizeof(int *));
    sg_num_nodes = malloc(MAX_SUBGRAPHS * sizeof(int));
    sg_node_op = malloc(MAX_SUBGRAPHS * sizeof(int *));
    sg_node_inputs = malloc(MAX_SUBGRAPHS * sizeof(int **));
    sg_node_num_in = malloc(MAX_SUBGRAPHS * sizeof(int *));
    sg_node_outputs = malloc(MAX_SUBGRAPHS * sizeof(int **));
    sg_node_num_out = malloc(MAX_SUBGRAPHS * sizeof(int *));

    i = 0;
    while (i < MAX_SUBGRAPHS) {
        sg_names[i] = malloc(64);
        sg_names[i][0] = 0;
        sg_temp_sizes[i] = malloc(16 * sizeof(int));
        sg_node_op[i] = malloc(MAX_SG_NODES * sizeof(int));
        sg_node_inputs[i] = malloc(MAX_SG_NODES * sizeof(int *));
        sg_node_num_in[i] = malloc(MAX_SG_NODES * sizeof(int));
        sg_node_outputs[i] = malloc(MAX_SG_NODES * sizeof(int *));
        sg_node_num_out[i] = malloc(MAX_SG_NODES * sizeof(int));
        j = 0;
        while (j < MAX_SG_NODES) {
            sg_node_inputs[i][j] = malloc(MAX_SG_IO * sizeof(int));
            sg_node_outputs[i][j] = malloc(MAX_SG_IO * sizeof(int));
            j = j + 1;
        }
        i = i + 1;
    }
    g_num_subgraphs = 0;

    sg_b2n = 0 - 1;
    sg_n2b = 0 - 1;
    sg_nib_add = 0 - 1;
    sg_nib_and = 0 - 1;
    sg_nib_or = 0 - 1;
    sg_nib_xor = 0 - 1;
    sg_nib_mul = 0 - 1;
}

int find_subgraph(char *name) {
    int i;
    i = 0;
    while (i < g_num_subgraphs) {
        if (str_eq(sg_names[i], name)) return i;
        i = i + 1;
    }
    return 0 - 1;
}

int load_neural_model() {
    char *p;
    int magic;
    int version;
    int n_tensors;
    int n_subgraphs;
    int i;
    int j;
    int k;
    int name_len;
    int ndims;
    int dims[8];
    int storage_type;
    int size;
    int nnz;
    int num_in;
    int num_out;
    char name[64];
    int *data;

    init_subgraph_storage();

    p = (char *)embedded_model;

    magic = read_int_from(&p);
    if (magic != 0x584E4E4F) {
        printf("Error: invalid model magic\n");
        return 0 - 1;
    }

    version = read_int_from(&p);
    n_tensors = read_int_from(&p);
    n_subgraphs = read_int_from(&p);

    /* Load tensors */
    i = 0;
    while (i < n_tensors) {
        name_len = read_int_from(&p);
        j = 0;
        while (j < name_len && j < 63) {
            name[j] = p[j];
            j = j + 1;
        }
        name[j] = 0;
        p = p + name_len;

        ndims = read_int_from(&p);
        size = 1;
        j = 0;
        while (j < ndims) {
            dims[j] = read_int_from(&p);
            g_tensor_dims[i][j] = dims[j];
            size = size * dims[j];
            j = j + 1;
        }
        g_tensor_ndims[i] = ndims;
        g_tensor_size[i] = size;

        if (version >= 3) {
            storage_type = read_int_from(&p);
        } else {
            read_int_from(&p);  /* data_type, ignored */
            storage_type = 0;
        }

        if (storage_type == 1) {
            /* Sparse COO */
            nnz = read_int_from(&p);
            g_sparse_nnz[i] = nnz;
            g_sparse_idx[i] = malloc(nnz * sizeof(int));
            g_sparse_val[i] = malloc(nnz * sizeof(int));
            j = 0;
            while (j < nnz) {
                g_sparse_idx[i][j] = read_int_from(&p);
                j = j + 1;
            }
            j = 0;
            while (j < nnz) {
                g_sparse_val[i][j] = read_int_from(&p);
                j = j + 1;
            }
            /* Reconstruct dense for compatibility */
            data = malloc(size * sizeof(int));
            j = 0;
            while (j < size) { data[j] = 0; j = j + 1; }
            j = 0;
            while (j < nnz) {
                data[g_sparse_idx[i][j]] = g_sparse_val[i][j];
                j = j + 1;
            }
            g_tensor_data[i] = data;
        } else {
            /* Dense */
            size = read_int_from(&p);
            g_tensor_size[i] = size;
            data = malloc(size * sizeof(int));
            j = 0;
            while (j < size) {
                data[j] = read_int_from(&p);
                j = j + 1;
            }
            g_tensor_data[i] = data;
        }

        /* Map to named pointers for backward compatibility */
        if (str_eq(name, "b2n_W1")) b2n_W1 = data;
        else if (str_eq(name, "b2n_W2")) b2n_W2 = data;
        else if (str_eq(name, "n2b_W1")) n2b_W1 = data;
        else if (str_eq(name, "n2b_W2")) n2b_W2 = data;
        else if (str_eq(name, "nib_add_W1")) nib_add_W1 = data;
        else if (str_eq(name, "nib_add_W2_sum")) nib_add_W2s = data;
        else if (str_eq(name, "nib_add_W2_cout")) nib_add_W2c = data;
        else if (str_eq(name, "nib_mul_W1")) nib_mul_W1 = data;
        else if (str_eq(name, "nib_mul_W2_lo")) nib_mul_W2l = data;
        else if (str_eq(name, "nib_mul_W2_hi")) nib_mul_W2h = data;
        else if (str_eq(name, "nib_and_W1")) nib_and_W1 = data;
        else if (str_eq(name, "nib_and_W2")) nib_and_W2 = data;
        else if (str_eq(name, "nib_or_W1")) nib_or_W1 = data;
        else if (str_eq(name, "nib_or_W2")) nib_or_W2 = data;
        else if (str_eq(name, "nib_xor_W1")) nib_xor_W1 = data;
        else if (str_eq(name, "nib_xor_W2")) nib_xor_W2 = data;
        else if (str_eq(name, "shl_result")) shl_res = data;
        else if (str_eq(name, "shl_overflow")) shl_over = data;
        else if (str_eq(name, "shr_result")) shr_res = data;
        else if (str_eq(name, "shr_underflow")) shr_under = data;

        i = i + 1;
    }
    g_num_tensors = n_tensors;

    /* Load subgraphs (v3 only) */
    if (version >= 3) {
        i = 0;
        while (i < n_subgraphs) {
            name_len = read_int_from(&p);
            j = 0;
            while (j < name_len && j < 63) {
                sg_names[i][j] = p[j];
                j = j + 1;
            }
            sg_names[i][j] = 0;
            p = p + name_len;

            sg_num_inputs[i] = read_int_from(&p);
            sg_num_outputs[i] = read_int_from(&p);
            sg_num_temps[i] = read_int_from(&p);
            j = 0;
            while (j < sg_num_temps[i]) {
                sg_temp_sizes[i][j] = read_int_from(&p);
                j = j + 1;
            }

            sg_num_nodes[i] = read_int_from(&p);
            j = 0;
            while (j < sg_num_nodes[i]) {
                sg_node_op[i][j] = read_int_from(&p);
                num_in = read_int_from(&p);
                sg_node_num_in[i][j] = num_in;
                k = 0;
                while (k < num_in) {
                    sg_node_inputs[i][j][k] = read_int_from(&p);
                    k = k + 1;
                }
                num_out = read_int_from(&p);
                sg_node_num_out[i][j] = num_out;
                k = 0;
                while (k < num_out) {
                    sg_node_outputs[i][j][k] = read_int_from(&p);
                    k = k + 1;
                }
                j = j + 1;
            }

            /* Cache known subgraph indices */
            if (str_eq(sg_names[i], "b2n")) sg_b2n = i;
            else if (str_eq(sg_names[i], "n2b")) sg_n2b = i;
            else if (str_eq(sg_names[i], "nib_add")) sg_nib_add = i;
            else if (str_eq(sg_names[i], "nib_and")) sg_nib_and = i;
            else if (str_eq(sg_names[i], "nib_or")) sg_nib_or = i;
            else if (str_eq(sg_names[i], "nib_xor")) sg_nib_xor = i;
            else if (str_eq(sg_names[i], "nib_mul")) sg_nib_mul = i;

            i = i + 1;
        }
        g_num_subgraphs = n_subgraphs;
    }

    model_loaded = 1;
    return 0;
}

/* ============ Neural Computation Primitives (Fixed-Point) ============ */
/* All values are 16.16 fixed-point int. One-hot = 0 or FP_ONE (65536). */

/* Softmax over array of length n, temperature-scaled */
void nn_softmax(int *out, int *in, int n, int temp) {
    int i;
    int max_val;
    int sum;

    max_val = in[0];
    i = 1;
    while (i < n) {
        if (in[i] > max_val) max_val = in[i];
        i = i + 1;
    }
    sum = 0;
    i = 0;
    while (i < n) {
        out[i] = fp_exp(fp_mul(in[i] - max_val, temp));
        sum = sum + out[i];
        i = i + 1;
    }
    if (sum > 0) {
        i = 0;
        while (i < n) {
            out[i] = fp_div(out[i], sum);
            i = i + 1;
        }
    }
}

/* MatMul: out[n] = in[m] @ W[m][n], all 16.16 FP.
 * Each term: fp_mul(in[i], W[i*n+j]) = (in[i]/256)*(W[i*n+j]/256).
 * Accumulate in int — safe because one-hot inputs have at most 1 non-zero. */
void nn_matmul_fp(int *out, int *in, int *W, int m, int n) {
    int i;
    int j;
    int acc;

    j = 0;
    while (j < n) {
        acc = 0;
        i = 0;
        while (i < m) {
            acc = acc + fp_mul(in[i], W[i * n + j]);
            i = i + 1;
        }
        out[j] = acc;
        j = j + 1;
    }
}

/* Argmax */
int nn_argmax(int *v, int n) {
    int best;
    int i;
    best = 0;
    i = 1;
    while (i < n) {
        if (v[i] > v[best]) best = i;
        i = i + 1;
    }
    return best;
}

/* ============ Subgraph Executor ============ */

/* Resolve a node reference to a data pointer.
 * ref >= 0: global tensor index
 * ref < 0: local ref:
 *   -1..-num_inputs: subgraph inputs
 *   -(num_inputs+1)..-(num_inputs+num_temps): temps
 *   -(num_inputs+num_temps+1)..: outputs */
int *sg_resolve(int ref, int sg, int **inputs, int **outputs, int **temps) {
    int local;
    int ni;
    int nt;
    if (ref >= 0) return g_tensor_data[ref];
    local = (0 - ref) - 1;
    ni = sg_num_inputs[sg];
    nt = sg_num_temps[sg];
    if (local < ni) return inputs[local];
    local = local - ni;
    if (local < nt) return temps[local];
    local = local - nt;
    return outputs[local];
}

int sg_resolve_size(int ref, int sg, int *in_sizes, int *out_sizes) {
    int local;
    int ni;
    int nt;
    if (ref >= 0) return g_tensor_size[ref];
    local = (0 - ref) - 1;
    ni = sg_num_inputs[sg];
    nt = sg_num_temps[sg];
    if (local < ni) return in_sizes[local];
    local = local - ni;
    if (local < nt) return sg_temp_sizes[sg][local];
    local = local - nt;
    return out_sizes[local];
}

/* Sparse matmul: out = in @ W_sparse (COO format) */
void sg_sparse_matmul(int *out, int *in, int tensor_idx, int out_size) {
    int i;
    int nnz;
    int ncols;
    int row;
    int col;
    int *sp_idx;
    int *sp_val;

    nnz = g_sparse_nnz[tensor_idx];
    ncols = g_tensor_dims[tensor_idx][1];
    sp_idx = g_sparse_idx[tensor_idx];
    sp_val = g_sparse_val[tensor_idx];

    i = 0;
    while (i < out_size) { out[i] = 0; i = i + 1; }

    i = 0;
    while (i < nnz) {
        row = sp_idx[i] / ncols;
        col = sp_idx[i] % ncols;
        out[col] = out[col] + fp_mul(in[row], sp_val[i]);
        i = i + 1;
    }
}

void run_subgraph(int sg, int **inputs, int **outputs, int *in_sizes, int *out_sizes) {
    int **temps;
    int n;
    int i;
    int j;
    int op;
    int *src;
    int *dst;
    int *src2;
    int src_size;
    int dst_size;
    int w_idx;
    int m;
    int offset;
    int len;

    n = sg_num_temps[sg];
    temps = malloc(n * sizeof(int *));
    i = 0;
    while (i < n) {
        temps[i] = malloc(sg_temp_sizes[sg][i] * sizeof(int));
        j = 0;
        while (j < sg_temp_sizes[sg][i]) { temps[i][j] = 0; j = j + 1; }
        i = i + 1;
    }

    /* Execute nodes */
    i = 0;
    while (i < sg_num_nodes[sg]) {
        op = sg_node_op[sg][i];
        dst = sg_resolve(sg_node_outputs[sg][i][0], sg, inputs, outputs, temps);
        dst_size = sg_resolve_size(sg_node_outputs[sg][i][0], sg, in_sizes, out_sizes);

        if (op == 5) {
            /* OP_MATMUL: dst = src @ weight_tensor */
            src = sg_resolve(sg_node_inputs[sg][i][0], sg, inputs, outputs, temps);
            w_idx = sg_node_inputs[sg][i][1];
            src_size = sg_resolve_size(sg_node_inputs[sg][i][0], sg, in_sizes, out_sizes);
            /* Use sparse matmul if tensor has sparse data */
            if (w_idx >= 0 && g_sparse_idx[w_idx] != 0) {
                sg_sparse_matmul(dst, src, w_idx, dst_size);
            } else {
                m = src_size;
                nn_matmul_fp(dst, src, g_tensor_data[w_idx], m, dst_size);
            }
        }
        else if (op == 10) {
            /* OP_SOFTMAX */
            src = sg_resolve(sg_node_inputs[sg][i][0], sg, inputs, outputs, temps);
            nn_softmax(dst, src, dst_size, FP_ONE);
        }
        else if (op == 14) {
            /* OP_CONCAT: concatenate all inputs */
            offset = 0;
            j = 0;
            while (j < sg_node_num_in[sg][i]) {
                src = sg_resolve(sg_node_inputs[sg][i][j], sg, inputs, outputs, temps);
                src_size = sg_resolve_size(sg_node_inputs[sg][i][j], sg, in_sizes, out_sizes);
                m = 0;
                while (m < src_size) {
                    dst[offset + m] = src[m];
                    m = m + 1;
                }
                offset = offset + src_size;
                j = j + 1;
            }
        }
        else if (op == 15) {
            /* OP_SLICE: dst = src[start:end] */
            src = sg_resolve(sg_node_inputs[sg][i][0], sg, inputs, outputs, temps);
            offset = sg_node_inputs[sg][i][1];  /* start */
            len = sg_node_inputs[sg][i][2] - offset;  /* end - start */
            j = 0;
            while (j < len) {
                dst[j] = src[offset + j];
                j = j + 1;
            }
        }
        else if (op == 16) {
            /* OP_SCALE: dst = src * scalar */
            src = sg_resolve(sg_node_inputs[sg][i][0], sg, inputs, outputs, temps);
            src_size = sg_resolve_size(sg_node_inputs[sg][i][0], sg, in_sizes, out_sizes);
            m = sg_node_inputs[sg][i][1];  /* scalar value */
            j = 0;
            while (j < src_size) {
                dst[j] = fp_mul(src[j], m);
                j = j + 1;
            }
        }

        i = i + 1;
    }

    /* Free temps */
    i = 0;
    while (i < n) {
        free(temps[i]);
        i = i + 1;
    }
    free(temps);
}

/* ============ Neural Byte/Nibble Operations ============ */
/* Thin wrappers that call subgraphs when available, else use hardcoded path */

/* One-hot encode a byte value */
void encode_byte(int *out, int val) {
    int i;
    i = 0;
    while (i < 256) { out[i] = 0; i = i + 1; }
    out[val & 0xFF] = FP_ONE;
}

int decode_byte(int *v) {
    return nn_argmax(v, 256);
}

/* Byte to nibbles via subgraph or model weights */
void neural_b2n(int *high, int *low, int *byte_oh) {
    int *sg_in[1];
    int *sg_out[2];
    int in_sz[1];
    int out_sz[2];

    if (sg_b2n >= 0) {
        sg_in[0] = byte_oh;
        sg_out[0] = high;
        sg_out[1] = low;
        in_sz[0] = 256;
        out_sz[0] = 16;
        out_sz[1] = 16;
        run_subgraph(sg_b2n, sg_in, sg_out, in_sz, out_sz);
    } else {
        /* Fallback: hardcoded path for v2 models */
        int *h;
        int *out;
        int i;
        h = malloc(256 * 4);
        out = malloc(32 * 4);
        nn_matmul_fp(h, byte_oh, b2n_W1, 256, 256);
        nn_matmul_fp(out, h, b2n_W2, 256, 32);
        i = 0;
        while (i < 16) {
            high[i] = out[i];
            low[i] = out[16 + i];
            i = i + 1;
        }
        free(h);
        free(out);
    }
}

/* Nibbles to byte via subgraph or model weights + softmax */
void neural_n2b(int *byte_oh, int *high, int *low) {
    int *sg_in[2];
    int *sg_out[1];
    int in_sz[2];
    int out_sz[1];

    if (sg_n2b >= 0) {
        sg_in[0] = high;
        sg_in[1] = low;
        sg_out[0] = byte_oh;
        in_sz[0] = 16;
        in_sz[1] = 16;
        out_sz[0] = 256;
        run_subgraph(sg_n2b, sg_in, sg_out, in_sz, out_sz);
    } else {
        int *combined;
        int *addr;
        int *addr_soft;
        int i;
        combined = malloc(32 * 4);
        addr = malloc(256 * 4);
        addr_soft = malloc(256 * 4);
        i = 0;
        while (i < 16) {
            combined[i] = high[i];
            combined[16 + i] = low[i];
            i = i + 1;
        }
        nn_matmul_fp(addr, combined, n2b_W1, 32, 256);
        nn_softmax(addr_soft, addr, 256, 100 * 65536);
        nn_matmul_fp(byte_oh, addr_soft, n2b_W2, 256, 256);
        free(combined);
        free(addr);
        free(addr_soft);
    }
}

/* Nibble add with carry via subgraph */
void neural_nib_add(int *sum_out, int *cout, int *a, int *b, int *cin) {
    int *sg_in[3];
    int *sg_out[2];
    int in_sz[3];
    int out_sz[2];

    if (sg_nib_add >= 0) {
        sg_in[0] = a;
        sg_in[1] = b;
        sg_in[2] = cin;
        sg_out[0] = sum_out;
        sg_out[1] = cout;
        in_sz[0] = 16;
        in_sz[1] = 16;
        in_sz[2] = 2;
        out_sz[0] = 16;
        out_sz[1] = 2;
        run_subgraph(sg_nib_add, sg_in, sg_out, in_sz, out_sz);
    } else {
        int *combined;
        int *addr;
        int *addr_soft;
        int i;
        combined = malloc(34 * 4);
        addr = malloc(512 * 4);
        addr_soft = malloc(512 * 4);
        i = 0;
        while (i < 16) { combined[i] = a[i]; i = i + 1; }
        i = 0;
        while (i < 16) { combined[16 + i] = b[i]; i = i + 1; }
        combined[32] = cin[0];
        combined[33] = cin[1];
        nn_matmul_fp(addr, combined, nib_add_W1, 34, 512);
        nn_softmax(addr_soft, addr, 512, 100 * 65536);
        nn_matmul_fp(sum_out, addr_soft, nib_add_W2s, 512, 16);
        nn_matmul_fp(cout, addr_soft, nib_add_W2c, 512, 2);
        free(combined);
        free(addr);
        free(addr_soft);
    }
}

/* Nibble bitwise op via subgraph */
void neural_nib_op(int *result, int *a, int *b, int *W1, int *W2) {
    int sg_idx;
    int *sg_in[2];
    int *sg_out[1];
    int in_sz[2];
    int out_sz[1];

    /* Determine which subgraph to use based on W1 pointer */
    sg_idx = 0 - 1;
    if (W1 == nib_and_W1) sg_idx = sg_nib_and;
    else if (W1 == nib_or_W1) sg_idx = sg_nib_or;
    else if (W1 == nib_xor_W1) sg_idx = sg_nib_xor;

    if (sg_idx >= 0) {
        sg_in[0] = a;
        sg_in[1] = b;
        sg_out[0] = result;
        in_sz[0] = 16;
        in_sz[1] = 16;
        out_sz[0] = 16;
        run_subgraph(sg_idx, sg_in, sg_out, in_sz, out_sz);
    } else {
        int *combined;
        int *addr;
        int *addr_soft;
        int i;
        combined = malloc(32 * 4);
        addr = malloc(256 * 4);
        addr_soft = malloc(256 * 4);
        i = 0;
        while (i < 16) { combined[i] = a[i]; i = i + 1; }
        i = 0;
        while (i < 16) { combined[16 + i] = b[i]; i = i + 1; }
        nn_matmul_fp(addr, combined, W1, 32, 256);
        nn_softmax(addr_soft, addr, 256, 100 * 65536);
        nn_matmul_fp(result, addr_soft, W2, 256, 16);
        free(combined);
        free(addr);
        free(addr_soft);
    }
}

/* Nibble multiply via subgraph */
void neural_nib_mul(int *lo_out, int *hi_out, int *a, int *b) {
    int *sg_in[2];
    int *sg_out[2];
    int in_sz[2];
    int out_sz[2];

    if (sg_nib_mul >= 0) {
        sg_in[0] = a;
        sg_in[1] = b;
        sg_out[0] = lo_out;
        sg_out[1] = hi_out;
        in_sz[0] = 16;
        in_sz[1] = 16;
        out_sz[0] = 16;
        out_sz[1] = 16;
        run_subgraph(sg_nib_mul, sg_in, sg_out, in_sz, out_sz);
    } else {
        int *combined;
        int *addr;
        int *addr_soft;
        int i;
        combined = malloc(32 * 4);
        addr = malloc(256 * 4);
        addr_soft = malloc(256 * 4);
        i = 0;
        while (i < 16) { combined[i] = a[i]; i = i + 1; }
        i = 0;
        while (i < 16) { combined[16 + i] = b[i]; i = i + 1; }
        nn_matmul_fp(addr, combined, nib_mul_W1, 32, 256);
        nn_softmax(addr_soft, addr, 256, 100 * 65536);
        nn_matmul_fp(lo_out, addr_soft, nib_mul_W2l, 256, 16);
        nn_matmul_fp(hi_out, addr_soft, nib_mul_W2h, 256, 16);
        free(combined);
        free(addr);
        free(addr_soft);
    }
}

/* ============ NVal: 32-bit integer as 4 one-hot byte vectors ============ */
/* NVal = int[1024] = 4 * 256 one-hot slots, each 0 or FP_ONE */
/* Layout: bytes 0-255 = byte 0 (LSB), 256-511 = byte 1, etc. */

int *nval_new() {
    int *v;
    int i;
    v = malloc(1024 * 4);
    i = 0;
    while (i < 1024) { v[i] = 0; i = i + 1; }
    /* Default: all bytes = 0 (one-hot at index 0) */
    v[0] = FP_ONE;
    v[256] = FP_ONE;
    v[512] = FP_ONE;
    v[768] = FP_ONE;
    return v;
}

void nval_encode(int *v, int val) {
    int i;
    i = 0;
    while (i < 4) {
        encode_byte(v + i * 256, (val >> (i * 8)) & 0xFF);
        i = i + 1;
    }
}

int nval_decode(int *v) {
    int i;
    int val;
    val = 0;
    i = 0;
    while (i < 4) {
        val = val | (decode_byte(v + i * 256) << (i * 8));
        i = i + 1;
    }
    /* Sign extend: if bit 31 set, make negative */
    if ((val & 0x80000000) != 0) {
        /* val is already negative in two's complement on 32-bit int */
    }
    return val;
}

void nval_copy(int *dst, int *src) {
    int i;
    i = 0;
    while (i < 1024) { dst[i] = src[i]; i = i + 1; }
}

/* ============ Neural 32-bit Operations ============ */

/* Neural addition: a + b using nibble add with carry */
void neural_add(int *result, int *a, int *b) {
    int ah[16], al[16], bh[16], bl[16];
    int sum_l[16], sum_h[16], carry[2];
    int i;

    carry[0] = FP_ONE; carry[1] = 0;

    i = 0;
    while (i < 4) {
        neural_b2n(ah, al, a + i * 256);
        neural_b2n(bh, bl, b + i * 256);
        neural_nib_add(sum_l, carry, al, bl, carry);
        neural_nib_add(sum_h, carry, ah, bh, carry);
        neural_n2b(result + i * 256, sum_h, sum_l);
        i = i + 1;
    }
}

/* Neural negate: ~x + 1 */
void neural_negate(int *result, int *x) {
    int xh[16], xl[16], oh[16], ol[16], rh[16], rl[16];
    int sum_l[16], sum_h[16], carry[2];
    int ones[256];
    int zero_nib[16];
    int *inv;
    int i;

    inv = malloc(1024 * 4);
    encode_byte(ones, 0xFF);

    /* XOR each byte with 0xFF */
    i = 0;
    while (i < 4) {
        neural_b2n(xh, xl, x + i * 256);
        neural_b2n(oh, ol, ones);
        neural_nib_op(rh, xh, oh, nib_xor_W1, nib_xor_W2);
        neural_nib_op(rl, xl, ol, nib_xor_W1, nib_xor_W2);
        neural_n2b(inv + i * 256, rh, rl);
        i = i + 1;
    }

    /* Add 1 */
    carry[0] = 0; carry[1] = FP_ONE;
    i = 0;
    while (i < 16) { zero_nib[i] = 0; i = i + 1; }
    zero_nib[0] = FP_ONE;

    i = 0;
    while (i < 4) {
        neural_b2n(xh, xl, inv + i * 256);
        neural_nib_add(sum_l, carry, xl, zero_nib, carry);
        neural_nib_add(sum_h, carry, xh, zero_nib, carry);
        neural_n2b(result + i * 256, sum_h, sum_l);
        i = i + 1;
    }
    free(inv);
}

void neural_sub(int *result, int *a, int *b) {
    int *neg_b;
    neg_b = nval_new();
    neural_negate(neg_b, b);
    neural_add(result, a, neg_b);
    free(neg_b);
}

/* Neural bitwise operations */
void neural_bitwise(int *result, int *a, int *b, int *W1, int *W2) {
    int ah[16], al[16], bh[16], bl[16], rh[16], rl[16];
    int i;
    i = 0;
    while (i < 4) {
        neural_b2n(ah, al, a + i * 256);
        neural_b2n(bh, bl, b + i * 256);
        neural_nib_op(rh, ah, bh, W1, W2);
        neural_nib_op(rl, al, bl, W1, W2);
        neural_n2b(result + i * 256, rh, rl);
        i = i + 1;
    }
}

/* Neural shift left by 1 */
void neural_shl1(int *result, int *x) {
    int h[16], l[16];
    int new_l[16], new_h[16], l_over[16], h_over[16];
    int carry[16];
    int i;
    int j;
    int k;
    int lv;
    int hv;
    int sr;
    int so;

    j = 0;
    while (j < 16) { carry[j] = 0; j = j + 1; }
    carry[0] = FP_ONE;

    i = 0;
    while (i < 4) {
        neural_b2n(h, l, x + i * 256);

        j = 0;
        while (j < 16) {
            new_l[j] = 0; l_over[j] = 0;
            new_h[j] = 0; h_over[j] = 0;
            j = j + 1;
        }
        j = 0;
        while (j < 16) {
            lv = l[j]; hv = h[j];
            k = 0;
            while (k < 16) {
                sr = shl_res[1 * 256 + j * 16 + k];
                so = shl_over[1 * 256 + j * 16 + k];
                new_l[k] = new_l[k] + fp_mul(lv, sr);
                l_over[k] = l_over[k] + fp_mul(lv, so);
                new_h[k] = new_h[k] + fp_mul(hv, sr);
                h_over[k] = h_over[k] + fp_mul(hv, so);
                k = k + 1;
            }
            j = j + 1;
        }

        neural_nib_op(new_l, new_l, carry, nib_or_W1, nib_or_W2);
        neural_nib_op(new_h, new_h, l_over, nib_or_W1, nib_or_W2);
        j = 0;
        while (j < 16) { carry[j] = h_over[j]; j = j + 1; }

        neural_n2b(result + i * 256, new_h, new_l);
        i = i + 1;
    }
}

/* Neural shift right by 1 */
void neural_shr1(int *result, int *x) {
    int h[16], l[16];
    int new_l[16], new_h[16], l_under[16], h_under[16];
    int carry[16];
    int i;
    int j;
    int k;
    int lv;
    int hv;
    int sr;
    int su;

    j = 0;
    while (j < 16) { carry[j] = 0; j = j + 1; }
    carry[0] = FP_ONE;

    i = 3;
    while (i >= 0) {
        neural_b2n(h, l, x + i * 256);

        j = 0;
        while (j < 16) {
            new_l[j] = 0; l_under[j] = 0;
            new_h[j] = 0; h_under[j] = 0;
            j = j + 1;
        }
        j = 0;
        while (j < 16) {
            lv = l[j]; hv = h[j];
            k = 0;
            while (k < 16) {
                sr = shr_res[1 * 256 + j * 16 + k];
                su = shr_under[1 * 256 + j * 16 + k];
                new_l[k] = new_l[k] + fp_mul(lv, sr);
                l_under[k] = l_under[k] + fp_mul(lv, su);
                new_h[k] = new_h[k] + fp_mul(hv, sr);
                h_under[k] = h_under[k] + fp_mul(hv, su);
                k = k + 1;
            }
            j = j + 1;
        }

        neural_nib_op(new_h, new_h, carry, nib_or_W1, nib_or_W2);
        neural_nib_op(new_l, new_l, h_under, nib_or_W1, nib_or_W2);
        j = 0;
        while (j < 16) { carry[j] = l_under[j]; j = j + 1; }

        neural_n2b(result + i * 256, new_h, new_l);
        i = i - 1;
    }
}

/* Neural multiply via schoolbook nibble multiplication */
void neural_mul(int *result, int *a, int *b) {
    int *a_nib;     /* 8 nibbles of a, each 16 ints = 128 total */
    int *b_nib;     /* 8 nibbles of b */
    int *acc;       /* 8 accumulator nibbles */
    int carry[2];
    int prod_lo[16];
    int prod_hi[16];
    int sum_tmp[16];
    int ah[16], al[16], bh[16], bl[16];
    int zero_nib_l[16];
    int i;
    int j;
    int k;
    int pos;

    a_nib = malloc(128 * 4);
    b_nib = malloc(128 * 4);
    acc = malloc(128 * 4);

    /* Extract 8 nibbles from a and b */
    i = 0;
    while (i < 4) {
        neural_b2n(ah, al, a + i * 256);
        k = 0;
        while (k < 16) {
            a_nib[(i * 2) * 16 + k] = al[k];
            a_nib[(i * 2 + 1) * 16 + k] = ah[k];
            k = k + 1;
        }
        neural_b2n(bh, bl, b + i * 256);
        k = 0;
        while (k < 16) {
            b_nib[(i * 2) * 16 + k] = bl[k];
            b_nib[(i * 2 + 1) * 16 + k] = bh[k];
            k = k + 1;
        }
        i = i + 1;
    }

    /* Initialize accumulator nibbles to zero */
    i = 0;
    while (i < 128) {
        acc[i] = 0;
        i = i + 1;
    }
    i = 0;
    while (i < 8) {
        acc[i * 16] = FP_ONE;
        i = i + 1;
    }

    /* Zero nibble for carry propagation */
    i = 0;
    while (i < 16) { zero_nib_l[i] = 0; i = i + 1; }
    zero_nib_l[0] = FP_ONE;

    /* Schoolbook: for each pair (i,j) where i+j < 8 */
    i = 0;
    while (i < 8) {
        j = 0;
        while (j < 8) {
            pos = i + j;
            if (pos < 8) {
                /* Multiply nibble a[i] * b[j] -> (prod_lo, prod_hi) */
                neural_nib_mul(prod_lo, prod_hi, a_nib + i * 16, b_nib + j * 16);

                /* Add prod_lo to acc[pos] with carry */
                carry[0] = FP_ONE; carry[1] = 0;
                neural_nib_add(sum_tmp, carry, acc + pos * 16, prod_lo, carry);
                k = 0;
                while (k < 16) { acc[pos * 16 + k] = sum_tmp[k]; k = k + 1; }

                /* Add prod_hi to acc[pos+1] with carry (if in range) */
                if (pos + 1 < 8) {
                    neural_nib_add(sum_tmp, carry, acc + (pos + 1) * 16, prod_hi, carry);
                    k = 0;
                    while (k < 16) { acc[(pos + 1) * 16 + k] = sum_tmp[k]; k = k + 1; }

                    /* Propagate remaining carry up */
                    pos = pos + 2;
                    while (pos < 8) {
                        if (carry[1] > FP_HALF) {
                            neural_nib_add(sum_tmp, carry, acc + pos * 16, zero_nib_l, carry);
                            k = 0;
                            while (k < 16) { acc[pos * 16 + k] = sum_tmp[k]; k = k + 1; }
                        }
                        pos = pos + 1;
                    }
                }
            }
            j = j + 1;
        }
        i = i + 1;
    }

    /* Pack 8 accumulator nibbles back into 4 bytes */
    i = 0;
    while (i < 4) {
        neural_n2b(result + i * 256, acc + (i * 2 + 1) * 16, acc + (i * 2) * 16);
        i = i + 1;
    }
    free(a_nib);
    free(b_nib);
    free(acc);
}

/* Neural is_zero check */
int neural_is_zero(int *x) {
    int prob;
    int i;
    /* Product of p(byte==0) — use fp_mul chain */
    prob = FP_ONE;
    i = 0;
    while (i < 4) {
        prob = fp_mul(prob, x[i * 256]);
        i = i + 1;
    }
    return prob > FP_HALF ? 1 : 0;
}

/* Neural is_negative (MSB set) */
int neural_is_negative(int *x) {
    int neg_w;
    int i;
    neg_w = 0;
    i = 128;
    while (i < 256) {
        neg_w = neg_w + x[768 + i]; /* byte 3, indices 128-255 */
        i = i + 1;
    }
    return neg_w > FP_HALF ? 1 : 0;
}

int neural_compare(int *a, int *b) {
    int *diff;
    int z;
    int n;
    diff = nval_new();
    neural_sub(diff, a, b);
    z = neural_is_zero(diff);
    n = neural_is_negative(diff);
    free(diff);
    if (z) return 0;
    if (n) return 0 - 1;
    return 1;
}

/* Neural divide via binary long division */
void neural_div(int *result, int *a, int *b) {
    int av;
    int bv;
    int a_neg;
    int b_neg;
    int *a_abs;
    int *b_abs;
    int *quotient;
    int *remainder;
    int *one;
    int *bit_mask;
    int *masked;
    int i;
    int bit_set;
    int cmp;

    av = nval_decode(a);
    bv = nval_decode(b);
    if (bv == 0) { nval_encode(result, 0); return; }

    a_neg = av < 0;
    b_neg = bv < 0;

    a_abs = nval_new();
    b_abs = nval_new();
    if (a_neg) neural_negate(a_abs, a); else nval_copy(a_abs, a);
    if (b_neg) neural_negate(b_abs, b); else nval_copy(b_abs, b);

    quotient = nval_new();
    remainder = nval_new();
    one = nval_new();
    bit_mask = nval_new();
    masked = nval_new();
    nval_encode(quotient, 0);
    nval_encode(remainder, 0);
    nval_encode(one, 1);

    i = 31;
    while (i >= 0) {
        neural_shl1(remainder, remainder);

        nval_encode(bit_mask, 1 << i);
        neural_bitwise(masked, a_abs, bit_mask, nib_and_W1, nib_and_W2);
        bit_set = !neural_is_zero(masked);

        if (bit_set) {
            neural_bitwise(remainder, remainder, one, nib_or_W1, nib_or_W2);
        }

        cmp = neural_compare(remainder, b_abs);
        if (cmp >= 0) {
            neural_sub(remainder, remainder, b_abs);
            neural_bitwise(quotient, quotient, bit_mask, nib_or_W1, nib_or_W2);
        }

        i = i - 1;
    }

    if (a_neg != b_neg) neural_negate(result, quotient);
    else nval_copy(result, quotient);

    free(a_abs); free(b_abs); free(quotient); free(remainder);
    free(one); free(bit_mask); free(masked);
}

void neural_mod(int *result, int *a, int *b) {
    int *q;
    int *qb;
    q = nval_new();
    qb = nval_new();
    neural_div(q, a, b);
    neural_mul(qb, q, b);
    neural_sub(result, a, qb);
    free(q); free(qb);
}

void neural_shl(int *result, int *x, int *amt) {
    int shift;
    int i;
    nval_copy(result, x);
    shift = nval_decode(amt);
    i = 0;
    while (i < shift && i < 32) {
        neural_shl1(result, result);
        i = i + 1;
    }
}

void neural_shr(int *result, int *x, int *amt) {
    int shift;
    int i;
    nval_copy(result, x);
    shift = nval_decode(amt);
    i = 0;
    while (i < shift && i < 32) {
        neural_shr1(result, result);
        i = i + 1;
    }
}

void neural_mask_byte(int *result, int *x) {
    int i;
    int j;
    j = 0;
    while (j < 256) { result[j] = x[j]; j = j + 1; }
    i = 1;
    while (i < 4) {
        j = 0;
        while (j < 256) { result[i * 256 + j] = 0; j = j + 1; }
        result[i * 256] = FP_ONE;
        i = i + 1;
    }
}

/* ============ VM State ============ */

int *reg_ax;
int *reg_sp;
int *reg_bp;
int *reg_pc;
int vm_halted;
int vm_exit_code;

int MEM_SIZE;
int *vm_memory;
int heap_ptr;

/* Stack helpers */
void vm_push(int *val) {
    int *eight;
    int addr;
    eight = nval_new();
    nval_encode(eight, 8);
    neural_sub(reg_sp, reg_sp, eight);
    addr = nval_decode(reg_sp);
    if (addr >= 0 && addr < MEM_SIZE) vm_memory[addr] = nval_decode(val);
    free(eight);
}

void vm_pop(int *val) {
    int addr;
    int *eight;
    addr = nval_decode(reg_sp);
    nval_encode(val, (addr >= 0 && addr < MEM_SIZE) ? vm_memory[addr] : 0);
    eight = nval_new();
    nval_encode(eight, 8);
    neural_add(reg_sp, reg_sp, eight);
    free(eight);
}

/* ============ VM Execution ============ */

int vm_step() {
    int pc_val;
    int instr_idx;
    int op;
    int imm;
    int *eight;
    int *imm_enc;
    int *ax;
    int *a;
    int cmp;
    int addr;
    int c;
    int size;
    int ptr;
    int *val;
    int *masked;

    if (vm_halted) return 0;

    pc_val = nval_decode(reg_pc);
    instr_idx = pc_val / 8;

    if (instr_idx < 0 || instr_idx >= program_code_len) {
        vm_halted = 1;
        return 0;
    }

    op = program_code[instr_idx][0];
    imm = program_code[instr_idx][1];

    /* Advance PC */
    eight = nval_new();
    nval_encode(eight, 8);
    neural_add(reg_pc, reg_pc, eight);
    free(eight);

    imm_enc = nval_new();
    nval_encode(imm_enc, imm);
    ax = nval_new();
    nval_copy(ax, reg_ax);
    a = nval_new();

    if (op == 0) { /* LEA */
        neural_add(reg_ax, reg_bp, imm_enc);
    }
    else if (op == 1) { /* IMM */
        nval_copy(reg_ax, imm_enc);
    }
    else if (op == 2) { /* JMP */
        nval_copy(reg_pc, imm_enc);
    }
    else if (op == 3) { /* JSR */
        vm_push(reg_pc);
        nval_copy(reg_pc, imm_enc);
    }
    else if (op == 4) { /* BZ */
        if (neural_is_zero(ax)) nval_copy(reg_pc, imm_enc);
    }
    else if (op == 5) { /* BNZ */
        if (!neural_is_zero(ax)) nval_copy(reg_pc, imm_enc);
    }
    else if (op == 6) { /* ENT */
        vm_push(reg_bp);
        nval_copy(reg_bp, reg_sp);
        neural_sub(reg_sp, reg_sp, imm_enc);
    }
    else if (op == 7) { /* ADJ */
        neural_add(reg_sp, reg_sp, imm_enc);
    }
    else if (op == 8) { /* LEV */
        nval_copy(reg_sp, reg_bp);
        vm_pop(reg_bp);
        vm_pop(reg_pc);
    }
    else if (op == 9) { /* LI */
        addr = nval_decode(ax);
        nval_encode(reg_ax, (addr >= 0 && addr < MEM_SIZE) ? vm_memory[addr] : 0);
    }
    else if (op == 10) { /* LC */
        addr = nval_decode(ax);
        val = nval_new();
        nval_encode(val, (addr >= 0 && addr < MEM_SIZE) ? vm_memory[addr] : 0);
        neural_mask_byte(reg_ax, val);
        free(val);
    }
    else if (op == 11) { /* SI */
        vm_pop(a);
        addr = nval_decode(a);
        if (addr >= 0 && addr < MEM_SIZE) vm_memory[addr] = nval_decode(ax);
    }
    else if (op == 12) { /* SC */
        vm_pop(a);
        addr = nval_decode(a);
        masked = nval_new();
        neural_mask_byte(masked, ax);
        if (addr >= 0 && addr < MEM_SIZE) vm_memory[addr] = nval_decode(masked);
        free(masked);
    }
    else if (op == 13) { /* PSH */
        vm_push(ax);
    }
    else if (op == 14) { /* OR */
        vm_pop(a);
        neural_bitwise(reg_ax, a, ax, nib_or_W1, nib_or_W2);
    }
    else if (op == 15) { /* XOR */
        vm_pop(a);
        neural_bitwise(reg_ax, a, ax, nib_xor_W1, nib_xor_W2);
    }
    else if (op == 16) { /* AND */
        vm_pop(a);
        neural_bitwise(reg_ax, a, ax, nib_and_W1, nib_and_W2);
    }
    else if (op == 17) { /* EQ */
        vm_pop(a);
        cmp = neural_compare(a, ax);
        nval_encode(reg_ax, cmp == 0 ? 1 : 0);
    }
    else if (op == 18) { /* NE */
        vm_pop(a);
        cmp = neural_compare(a, ax);
        nval_encode(reg_ax, cmp != 0 ? 1 : 0);
    }
    else if (op == 19) { /* LT */
        vm_pop(a);
        cmp = neural_compare(a, ax);
        nval_encode(reg_ax, cmp < 0 ? 1 : 0);
    }
    else if (op == 20) { /* GT */
        vm_pop(a);
        cmp = neural_compare(a, ax);
        nval_encode(reg_ax, cmp > 0 ? 1 : 0);
    }
    else if (op == 21) { /* LE */
        vm_pop(a);
        cmp = neural_compare(a, ax);
        nval_encode(reg_ax, cmp <= 0 ? 1 : 0);
    }
    else if (op == 22) { /* GE */
        vm_pop(a);
        cmp = neural_compare(a, ax);
        nval_encode(reg_ax, cmp >= 0 ? 1 : 0);
    }
    else if (op == 23) { /* SHL */
        vm_pop(a);
        neural_shl(reg_ax, a, ax);
    }
    else if (op == 24) { /* SHR */
        vm_pop(a);
        neural_shr(reg_ax, a, ax);
    }
    else if (op == 25) { /* ADD */
        vm_pop(a);
        neural_add(reg_ax, a, ax);
    }
    else if (op == 26) { /* SUB */
        vm_pop(a);
        neural_sub(reg_ax, a, ax);
    }
    else if (op == 27) { /* MUL */
        vm_pop(a);
        neural_mul(reg_ax, a, ax);
    }
    else if (op == 28) { /* DIV */
        vm_pop(a);
        neural_div(reg_ax, a, ax);
    }
    else if (op == 29) { /* MOD */
        vm_pop(a);
        neural_mod(reg_ax, a, ax);
    }
    else if (op == 34) { /* MALC */
        addr = nval_decode(reg_sp);
        size = (addr >= 0 && addr < MEM_SIZE) ? vm_memory[addr] : 0;
        ptr = heap_ptr;
        heap_ptr = heap_ptr + (size + 7) / 8;
        if (heap_ptr >= MEM_SIZE) heap_ptr = MEM_SIZE - 1;
        nval_encode(reg_ax, ptr);
    }
    else if (op == 35) { /* FREE */ }
    else if (op == 38) { /* EXIT */
        vm_exit_code = nval_decode(ax);
        vm_halted = 1;
        free(imm_enc); free(ax); free(a);
        return 0;
    }
    else if (op == 64) { /* GETCHAR */
        c = getchar();
        nval_encode(reg_ax, c);
    }
    else if (op == 65) { /* PUTCHAR */
        addr = nval_decode(reg_sp);
        c = (addr >= 0 && addr < MEM_SIZE) ? vm_memory[addr] : 0;
        putchar(c & 0xFF);
        fflush(stdout);
    }
    else {
        printf("Unknown opcode: %d at PC=%d\n", op, pc_val);
        vm_halted = 1;
        free(imm_enc); free(ax); free(a);
        return 0;
    }

    free(imm_enc);
    free(ax);
    free(a);
    return 1;
}

/* ============ Main ============ */

int main() {
    int i;

    FP_ONE = 65536;
    FP_HALF = 32768;
    MEM_SIZE = 0x20000;
    heap_ptr = 0x18000;

    vm_memory = malloc(MEM_SIZE * 4);
    i = 0;
    while (i < MEM_SIZE) { vm_memory[i] = 0; i = i + 1; }

    if (load_neural_model() != 0) {
        printf("Failed to load neural model\n");
        return 1;
    }

    reg_ax = nval_new();
    reg_sp = nval_new();
    reg_bp = nval_new();
    reg_pc = nval_new();
    nval_encode(reg_ax, 0);
    nval_encode(reg_sp, 0x10000);
    nval_encode(reg_bp, 0x10000);
    nval_encode(reg_pc, 0);
    vm_halted = 0;
    vm_exit_code = 0;

    i = 0;
    while (i < program_data_len) {
        vm_memory[0x10000 + i] = program_data[i];
        i = i + 1;
    }

    while (vm_step()) {}

    return vm_exit_code & 0xFF;
}

